// All recent records (used for both the header breakdown AND the feedback/other list)
const allClassified = $('filter recent').all().map(item => item.json);

if (allClassified.length === 0) return [];

const feedbacks = allClassified.filter(i => i.category === 'feedback');
const others = allClassified.filter(i => i.category === 'other');
const sponsors = allClassified.filter(i => i.category === 'sponsor');
const faqs = allClassified.filter(i => i.category === 'FAQ');
const spams = allClassified.filter(i => i.category === 'spam');
const acknowledges = allClassified.filter(i => i.category === 'acknowledge');

const totalProcessed = allClassified.length;
const needAttention = feedbacks.length + others.length + sponsors.length + faqs.length;
const filtered = spams.length + acknowledges.length;

if (feedbacks.length === 0 && others.length === 0) return [];

function commentBlock(item) {
  const videoId = item.video_id;
  const commentId = item.comment_id;
  const author = item.author || 'unknown';
  const likeCount = item.like_count ?? 0;
  const text = (item.text || '').slice(0, 280);

  const ytLink = (videoId && commentId)
    ? `https://www.youtube.com/watch?v=${videoId}&lc=${commentId}`
    : 'https://www.youtube.com';

  return {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*${author}* · 👍 ${likeCount}\n>>> ${text}\n<${ytLink}|🔗 Open comment>`
    }
  };
}

const blocks = [];

blocks.push({
  type: 'header',
  text: {
    type: 'plain_text',
    text: `📊 ${totalProcessed} processed · ${needAttention} need attention · ${filtered} filtered`
  }
});

blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text:
      `*${feedbacks.length}* feedback · *${others.length}* to handle · *${faqs.length}* FAQ with draft · *${sponsors.length}* sponsor\n` +
      `_Filtered: ${spams.length} spam · ${acknowledges.length} acknowledge_`
  }
});

blocks.push({ type: 'divider' });

if (feedbacks.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*💬 Feedback (${feedbacks.length})*` } });
  const TOP = 10;
  for (const item of feedbacks.slice(0, TOP)) blocks.push(commentBlock(item));
  if (feedbacks.length > TOP) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_… and ${feedbacks.length - TOP} more feedback — see Supabase for full detail_` }] });
  }
}

if (others.length > 0) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*❓ Other (${others.length})*` } });
  const TOP = 10;
  for (const item of others.slice(0, TOP)) blocks.push(commentBlock(item));
  if (others.length > TOP) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_… and ${others.length - TOP} more other — see Supabase for full detail_` }] });
  }
}

blocks.push({ type: 'divider' });
blocks.push({
  type: 'context',
  elements: [{
    type: 'mrkdwn',
    text: `🤖 Comment Triage Agent · ${new Date().toUTCString()}`
  }]
});

return { json: { blocks } };

const allClassified = $('filter recent').all().map(item => item.json);

if (allClassified.length === 0) return [];

const sponsors = allClassified.filter(i => i.category === 'sponsor');
if (sponsors.length === 0) return [];

const totalProcessed = allClassified.length;

const blocks = [];

blocks.push({
  type: 'header',
  text: { type: 'plain_text', text: `🤝 Sponsorship inquiries — ${sponsors.length} new` }
});

blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: `*${sponsors.length}* opportunities to qualify · ${totalProcessed} total comments in batch`
  }
});

blocks.push({ type: 'divider' });

for (const item of sponsors) {
  const videoId = item.video_id;
  const commentId = item.comment_id;
  const author = item.author || 'unknown';
  const likeCount = item.like_count ?? 0;
  const text = (item.text || '').slice(0, 500);
  const reasoning = item.reasoning;
  const authorChannelUrl = item.author_channel_url || 'https://youtube.com';

  const ytLink = (videoId && commentId)
    ? `https://www.youtube.com/watch?v=${videoId}&lc=${commentId}`
    : 'https://www.youtube.com';

  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*${author}* · 👍 ${likeCount}\n>>> ${text}` }
  });

  if (reasoning) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `🤖 _${reasoning}_` }] });
  }

  blocks.push({
    type: 'actions',
    elements: [
      { type: 'button', text: { type: 'plain_text', text: '🔗 Open comment' }, url: ytLink },
      { type: 'button', text: { type: 'plain_text', text: '👤 Brand channel' }, style: 'primary', url: authorChannelUrl }
    ]
  });

  blocks.push({ type: 'divider' });
}

blocks.push({
  type: 'context',
  elements: [{
    type: 'mrkdwn',
    text: `🤖 Comment Triage Agent · ${new Date().toUTCString()}`
  }]
});

return { json: { blocks } };

const processedIds = new Set(
  $('Get processed IDs').all().map(item => item.json.comment_id)
);

const allItems = $input.all();
const newItems = [];

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];
  const cid = item.json.snippet.topLevelComment.id;
  if (!processedIds.has(cid)) {
    newItems.push({
      json: item.json,
      pairedItem: { item: i }   // ← la riga che mancava
    });
  }
}

console.log(
  `Dedup: ${allItems.length} scaricati · ${newItems.length} nuovi · ${allItems.length - newItems.length} skippati`
);

return newItems;

// 1. Parsing della risposta dell'AI Agent
const aiText = $input.item.json.output;

let classification;
try {
  classification = JSON.parse(aiText);
} catch (e) {
  throw new Error(
    `AI Agent non ha restituito JSON valido. Output ricevuto: ${aiText.slice(0, 300)}`
  );
}

// 2. Recupero dei campi originali del commento via paired items
const original = $('Split commenti').item.json;
const snippet = original.snippet.topLevelComment.snippet;

// 3. Flat object con SCHEMA COMPLETO e null fallback su ogni campo opzionale.
//    Garantisce che TUTTI gli item abbiano le stesse 19 chiavi sempre presenti
//    (PostgREST batch insert fallisce se anche solo un campo è undefined invece di null).
return {
  json: {
    category: classification.category,
    confidence: classification.confidence,
    reasoning: classification.reasoning,
    commentId: original.snippet.topLevelComment.id,
    threadId: original.id,
    videoId: original.snippet.videoId,
    text: snippet.textOriginal ?? '',
    textHtml: snippet.textDisplay ?? null,
    author: snippet.authorDisplayName ?? null,
    authorChannelId: snippet.authorChannelId?.value ?? null,
    authorChannelUrl: snippet.authorChannelUrl ?? null,
    publishedAt: snippet.publishedAt ?? null,
    likeCount: snippet.likeCount ?? 0,
    totalReplies: original.snippet.totalReplyCount ?? 0,
    classifiedAt: new Date().toISOString(),
    replyDraft: null,
    replyConfidence: null,
    replyRationale: null,
    replyGeneratedAt: null,
  }
};

// 1. Parsing della risposta dell'AI Agent #2 (Generate FAQ reply)
const aiText = $input.item.json.output;

let reply;
try {
  reply = JSON.parse(aiText);
} catch (e) {
  throw new Error(
    `Generate FAQ reply non ha restituito JSON valido. Output ricevuto: ${aiText.slice(0, 300)}`
  );
}

// 2. Recupero del flat object già preparato da Parse classification
const classified = $('Route by category').item.json;

// 3. Una bozza è valida solo se reply_draft non è vuoto
const hasDraft = !!(reply.reply_draft && reply.reply_draft.length > 0);

// 4. Mapping esplicito chiave per chiave (stesso ORDINE di Parse classification1).
//    NON usare ...spread: cambia l'ordine dei campi e fa pignolare PostgREST nei batch insert.
return {
  json: {
    category: classified.category,
    confidence: classified.confidence,
    reasoning: classified.reasoning,
    commentId: classified.commentId,
    threadId: classified.threadId,
    videoId: classified.videoId,
    text: classified.text,
    textHtml: classified.textHtml,
    author: classified.author,
    authorChannelId: classified.authorChannelId,
    authorChannelUrl: classified.authorChannelUrl,
    publishedAt: classified.publishedAt,
    likeCount: classified.likeCount,
    totalReplies: classified.totalReplies,
    classifiedAt: classified.classifiedAt,
    replyDraft: hasDraft ? reply.reply_draft : null,
    replyConfidence: hasDraft ? reply.confidence : null,
    replyRationale: reply.rationale || null,
    replyGeneratedAt: hasDraft ? new Date().toISOString() : null,
  }
};

const cutoff = new Date(Date.now() - 15 * 60 * 1000).getTime();

const recent = $input.all().filter(item =>
  item.json.classified_at &&
  new Date(item.json.classified_at).getTime() > cutoff
);

console.log(`Filter Recent: ${$input.all().length} totali in DB → ${recent.length} recenti`);

return recent;;

// Test Comments — synthetic comment source for demo
// Replaces YouTube API HTTP Request to avoid pulling real user data
// Run mode: Run Once for All Items

function makeCommentThread(idx, text, author, likeCount, daysAgo, totalReplies = 0) {
  const runStart = ($execution && $execution.startedAt) ? $execution.startedAt : new Date().toISOString();
  const runId = runStart.replace(/[^0-9]/g, '').slice(0, 13);
  const id = `UgxDemo${String(idx).padStart(4, '0')}_${runId}AaABAg`;
  const authorChannelId = `UC${String(idx).padStart(6, '0')}DemoChan`;

  const d = new Date(runStart);
  d.setDate(d.getDate() - daysAgo);
  d.setHours(Math.floor(Math.random() * 24));
  d.setMinutes(Math.floor(Math.random() * 60));
  d.setSeconds(Math.floor(Math.random() * 60));
  const publishedAt = d.toISOString();

  const textDisplay = text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

  return {
    kind: 'youtube#commentThread',
    etag: `etag_demo_${idx}`,
    id,
    snippet: {
      channelId: 'UCDemoChannelTechReviews',
      videoId: 'demo_video_001',
      topLevelComment: {
        kind: 'youtube#comment',
        etag: `etag_demo_comment_${idx}`,
        id,
        snippet: {
          channelId: 'UCDemoChannelTechReviews',
          videoId: 'demo_video_001',
          textDisplay,
          textOriginal: text,
          authorDisplayName: author,
          authorProfileImageUrl: 'https://yt3.ggpht.com/demo-avatar.png',
          authorChannelUrl: `http://www.youtube.com/${author}`,
          authorChannelId: { value: authorChannelId },
          canRate: true,
          viewerRating: 'none',
          likeCount,
          publishedAt,
          updatedAt: publishedAt
        }
      },
      canReply: true,
      totalReplyCount: totalReplies,
      isPublic: true
    }
  };
}

